-- Tabla de Cuentas Contables
CREATE TABLE Accounts (
    AccountId INT IDENTITY(1,1) PRIMARY KEY NOT NULL,
    Code VARCHAR(30) NOT NULL,
    Name VARCHAR(150) NOT NULL,
    Type VARCHAR(50),
    ParentAccountCode VARCHAR(30) NOT NULL,
    Level INT,
    Sign VARCHAR(5) NOT NULL,
    Balance DECIMAL(18,2) NOT NULL,
    BankCode INT NOT NULL,
    FOREIGN KEY (BankCode) REFERENCES Banks(BankId),
    BankName VARCHAR(150) NOT NULL,
    BankAccountType VARCHAR(20) NOT NULL,
    CheckNumber INT NOT NULL,
    Currency VARCHAR(5) NOT NULL,
    CurrencyName VARCHAR(30) NOT NULL
);
SELECT * FROM Accounts ORDER BY Name
UPDATE Accounts SET Balance = 0 WHERE Code = '11101'
UPDATE Accounts SET Balance = 0 WHERE Code = '11201'


